1	import { Qwen2VLProcessor, Qwen2VLForConditionalGeneration, RawImage } from "../../../src/transformers.js";
2	
3	import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../../init.js";
4	
5	export default () => {
6	  const CONVERSATION = [
7	    {
8	      role: "user",
9	      content: [{ type: "text", text: "Hello" }],
10	    },
11	  ];
12	
13	  // Example adapted from https://huggingface.co/Qwen/Qwen2-VL-2B-Instruct
14	  const CONVERSATION_WITH_IMAGE = [
15	    {
16	      role: "user",
17	      content: [{ type: "image" }, { type: "text", text: "Describe this image." }],
18	    },
19	  ];
20	  // Empty white image
21	  const dims = [224, 224, 3];
22	  const image = new RawImage(new Uint8ClampedArray(dims[0] * dims[1] * dims[2]).fill(255), ...dims);
23	
24	  describe("Qwen2VLForConditionalGeneration", () => {
25	    const model_id = "hf-internal-testing/tiny-random-Qwen2VLForConditionalGeneration";
26	
27	    /** @type {Qwen2VLForConditionalGeneration} */
28	    let model;
29	    /** @type {Qwen2VLProcessor} */
30	    let processor;
31	    beforeAll(async () => {
32	      model = await Qwen2VLForConditionalGeneration.from_pretrained(model_id, DEFAULT_MODEL_OPTIONS);
33	      processor = await Qwen2VLProcessor.from_pretrained(model_id);
34	    }, MAX_MODEL_LOAD_TIME);
35	
36	    it(
37	      "forward",
38	      async () => {
39	        const text = processor.apply_chat_template(CONVERSATION_WITH_IMAGE, {
40	          add_generation_prompt: true,
41	        });
42	        const inputs = await processor(text, image);
43	        const { logits } = await model(inputs);
44	        expect(logits.dims).toEqual([1, 89, 152064]);
45	        expect(logits.mean().item()).toBeCloseTo(-0.0011299321195110679, 5);
46	      },
47	      MAX_TEST_EXECUTION_TIME,
48	    );
49	
50	    it(
51	      "text-only (batch_size=1)",
52	      async () => {
53	        const text = processor.apply_chat_template(CONVERSATION, {
54	          add_generation_prompt: true,
55	        });
56	        const inputs = await processor(text);
57	        const generate_ids = await model.generate({
58	          ...inputs,
59	          max_new_tokens: 10,
60	        });
